using namespace std;



string kata;

int len;

int prefixsum[100005];

int tmp;



int main(){

	cin>>kata;

	int r = kata.length();

	len = r;

	int l = 1;

	while(l<r){

		int mid = (l+r+1)>>1;



		memset(prefixsum, 0, sizeof(prefixsum));

		tmp =0;

		for(int i=0; i+mid <= len; i++){

			tmp += prefixsum[i];

			int nilpos = (kata[i] - '0') ^ (tmp & 1);

			if(nilpos){

				prefixsum[i+1] ++;

				prefixsum[i+mid] --;

			}

		}

		int sisa  = len - mid;

		for(int i=len-mid+1;i<len;i++){

			tmp += prefixsum[i];

			int nilpos = (kata[i] - '0') ^ (tmp & 1);

			if(nilpos == 0) sisa = i;else break;

		}

		if(sisa+1 >= mid){

			l = mid;

		}else{

			r = mid -1;

		}

	}	

	cout<<l<<"\n";

}

